 1	import type { FC } from 'react';
 2	import { Controller } from 'react-hook-form';
 3	
 4	import { ExternalLink } from '@components/common/ExternalLink/ExternalLink';
 5	import { FormGroupWithHelpText } from '@components/common/FormGroupWithHelpText/FormGroupWithHelpText';
 6	import { HelpIconPopover } from '@components/common/HelpIconPopover/HelpIconPopover';
 7	import { Stack, StackItem, TextInput } from '@patternfly/react-core';
 8	import { ForkliftTrans, useForkliftTranslation } from '@utils/i18n';
 9	import { VIRT_V2V_HELP_LINK } from '@utils/links';
10	
11	import { useCreatePlanFormContext } from '../../hooks/useCreatePlanFormContext';
12	
13	import { otherFormFieldLabels, OtherSettingsFormFieldId } from './constants';
14	
15	const RootDeviceField: FC = () => {
16	  const { t } = useForkliftTranslation();
17	  const { control } = useCreatePlanFormContext();
18	  const fieldId = OtherSettingsFormFieldId.RootDevice;
19	
20	  return (
21	    <FormGroupWithHelpText
22	      fieldId={fieldId}
23	      label={otherFormFieldLabels[fieldId]}
24	      labelIcon={
25	        <HelpIconPopover header={otherFormFieldLabels[fieldId]}>
26	          <ForkliftTrans>
27	            <Stack hasGutter>
28	              <StackItem>
29	                A root device is the storage device or partition that contains the root filesystem.
30	                For example, naming a root device "/dev/sda2" would mean to use the second partition
31	                on the first hard drive.
32	              </StackItem>
33	
34	              <StackItem>
35	                If you do not provide a root device, the first root device will be used. If the
36	                named root device does not exist or is not detected as a root device, the migration
37	                will fail.
38	              </StackItem>
39	
40	              <StackItem>
41	                <ExternalLink isInline href={VIRT_V2V_HELP_LINK}>
42	                  Learn more
43	                </ExternalLink>
44	              </StackItem>
45	            </Stack>
46	          </ForkliftTrans>
47	        </HelpIconPopover>
48	      }
49	      helperText={t(
50	        'Provide the storage device or partition that contains the root filesystem. If left blank, the first root device will be used.',
51	      )}
52	    >
53	      <Controller
54	        name={fieldId}
55	        control={control}
56	        render={({ field }) => (
57	          <TextInput
58	            id={field.name}
59	            value={field.value}
60	            onChange={(_event, value) => {
61	              field.onChange(value);
62	            }}
63	          />
64	        )}
65	      />
66	    </FormGroupWithHelpText>
67	  );
68	};
69	
70	export default RootDeviceField;

